module top_module(rst_n, rst, IRWr, im_dout, instr);input         rst_n;
   input         rst;
   input         IRWr; 
   input  [31:0] im_dout;
   output [31:0] instr;

   reg [31:0] instr;

   always @(posedge rst_n or posedge rst) begin
      if ( rst ) 
         instr <= 0;
      else if (IRWr)
         instr <= im_dout;
   end 

endmodule
